async function filterArticlesByTeam(articles: Article[], teamName: string): Promise<Article[]> {
  const filtered = [];
  const globalDiscardCount = new Map(); // Track discard rate per source

  for (const article of articles) {
    // Simple check: does article mention team name?
    const content = (article.title + ' ' + article.raw_content).toLowerCase();
    const teamMentioned = content.includes(teamName.toLowerCase());

    if (teamMentioned) {
      filtered.push({ ...article, relevance_confirmed: true });
    } else {
      // Track discard for global sources
      if (article.source.team_id === null) {
        globalDiscardCount.set(article.source_id, (globalDiscardCount.get(article.source_id) || 0) + 1);
      }
    }
  }

  // Flag low-relevance sources (>50% discarded)
  for (const [sourceId, discardCount] of globalDiscardCount.entries()) {
    const totalFromSource = articles.filter(a => a.source_id === sourceId).length;
    const discardRate = discardCount / totalFromSource;

    if (discardRate > 0.5) {
      await supabase.from('sources')
        .update({ status: 'flagged' })
        .eq('id', sourceId);

      await notifyAdmin({ sourceId, discardRate, teamName });
    }
  }

  return filtered;
}

