async function assembleNewsletter(teamId: string): Promise<Newsletter> {
  // Get team data
  const { data: team } = await supabase
    .from('teams')
    .select('*')
    .eq('id', teamId)
    .single();

  // Get latest articles for this team (from today's pipeline run)
  const today = new Date();
  today.setHours(0, 0, 0, 0);

  const { data: articles } = await supabase
    .from('articles')
    .select('*, sources(name)')
    .eq('team_id', teamId)
    .gte('created_at', today.toISOString())
    .order('created_at', { ascending: false });

  // Rank and select articles
  const selected = rankAndSelectArticles(articles);

  // Generate stat of the day
  const stat = await generateStatOfTheDay(team.name, articles);

  // Render HTML template
  const html = renderNewsletterTemplate({
    team,
    leadStory: selected.leadStory,
    quickHits: selected.quickHits,
    injuries: selected.injuries,
    statOfDay: stat,
    subscriber: null, // Will be filled per-subscriber
    newsletter: null // Will be filled after insert
  });

  // Generate subject line
  const subjectLine = `${team.name} Morning Briefing — ${new Date().toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}`;

  // Insert newsletter record
  const { data: newsletter } = await supabase
    .from('newsletters')
    .insert({
      team_id: teamId,
      subject_line: subjectLine,
      html_content: html,
      status: 'draft'
    })
    .select()
    .single();

  return newsletter;
}

