async function notifyAdmin(notification: {
  type: 'source_flagged' | 'pipeline_error' | 'low_relevance_source',
  data: any
}): Promise<void> {
  const adminEmail = Deno.env.get('ADMIN_EMAIL') || 'admin@nflwire.com';

  let subject = '';
  let html = '';

  switch (notification.type) {
    case 'source_flagged':
      subject = `Source Flagged: ${notification.data.url}`;
      html = `
        <h2>Source requires review</h2>
        <p><strong>URL:</strong> ${notification.data.url}</p>
        <p><strong>Team:</strong> ${notification.data.teamName}</p>
        <p><strong>Confidence:</strong> ${notification.data.confidence}%</p>
        <p><strong>Reason:</strong> ${notification.data.reason}</p>
        <a href="https://[PROJECT-URL]/admin/sources">Review in Admin</a>
      `;
      break;

    case 'pipeline_error':
      subject = `Pipeline Error: ${notification.data.teamName}`;
      html = `
        <h2>Content pipeline failed</h2>
        <p><strong>Team:</strong> ${notification.data.teamName}</p>
        <p><strong>Error:</strong> ${notification.data.error}</p>
        <p><strong>Timestamp:</strong> ${new Date().toISOString()}</p>
      `;
      break;

    case 'low_relevance_source':
      subject = `Low Relevance Source: ${notification.data.sourceId}`;
      html = `
        <h2>Source has high discard rate</h2>
        <p><strong>Source ID:</strong> ${notification.data.sourceId}</p>
        <p><strong>Team:</strong> ${notification.data.teamName}</p>
        <p><strong>Discard Rate:</strong> ${(notification.data.discardRate * 100).toFixed(1)}%</p>
        <a href="https://[PROJECT-URL]/admin/sources">Review in Admin</a>
      `;
      break;
  }

  await fetch('https://api.resend.com/emails', {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${Deno.env.get('RESEND_API_KEY')}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      from: 'NFL Wire Alerts <alerts@nflwire.com>',
      to: adminEmail,
      subject,
      html
    })
  });
}

