class AppError extends Error {
  constructor(
    public code: string,
    message: string,
    public statusCode: number = 500,
    public metadata?: any
  ) {
    super(message);
    this.name = 'AppError';
  }
}

function logError(error: Error | AppError, context: string): void {
  console.error(`[${context}] ${error.message}`, {
    name: error.name,
    stack: error.stack,
    ...(error instanceof AppError ? { code: error.code, metadata: error.metadata } : {})
  });

  // Optional: Send to error tracking service (Sentry, etc.)
}

